import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.web.client.RestTemplate;

import java.net.URI;
import java.net.URISyntaxException;
import java.util.List;

@RestController
public class WebhookController {

    @Autowired
    private RestTemplate restTemplate;

    @PostMapping("/webhook")
    public ResponseEntity<String> handleWebhook(@RequestBody WebhookRequest request) {
        List<String> urls = request.getUrls();
        StringBuilder responseContent = new StringBuilder();

        for (String url : urls) {
            if (isValidUrl(url)) {
                try {
                    ResponseEntity<String> response = restTemplate.getForEntity(url, String.class);
                    responseContent.append(response.getBody()).append("\n");
                } catch (Exception e) {
                    return ResponseEntity.status(500).body("Error fetching URL: " + url);
                }
            } else {
                return ResponseEntity.badRequest().body("Invalid URL: " + url);
            }
        }
        return ResponseEntity.ok(responseContent.toString());
    }

    private boolean isValidUrl(String url) {
        try {
            URI uri = new URI(url);
            return uri.getScheme().equals("http") || uri.getScheme().equals("https");
        } catch (URISyntaxException e) {
            return false;
        }
    }
}

class WebhookRequest {
    private List<String> urls;

    public List<String> getUrls() {
        return urls;
    }

    public void setUrls(List<String> urls) {
        this.urls = urls;
    }
}